#[tokio::test]
async fn test_concurrent_basic() {
    // Concurrent crawling fetches all pages with max_concurrent workers
    let engine_config: CrawlConfig =
        serde_json::from_str("{\"max_concurrent\":3,\"max_depth\":1}").expect("config should parse");
    let engine = create_engine(Some(engine_config)).expect("handle creation should succeed");
    let url = std::env::var("MOCK_SERVER_CONCURRENT_BASIC").unwrap_or_else(|_| {
        let _ = common::mock_server_url();
        std::env::var("MOCK_SERVER_CONCURRENT_BASIC")
            .unwrap_or_else(|_| format!("{}/fixtures/{}", common::mock_server_url(), "concurrent_basic"))
    });
    let result = crawl(&engine, &url).await.expect("should succeed");
    assert_eq!(result.pages.len(), 6, "equals assertion failed");
    assert!(result.pages.len() >= 6, "expected >= 6");
}

